var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"군대 놈들과 엮이는 건 우리 사무실 방침과는 다르지만……. 어쩔 수 없지.","JPN":"軍人どもと関わるのは我が事務所の方針に反しているが……仕方ないか。","ENG":"I don’t like working with the military, but... what choice do I have.","TWN":"和軍隊打交道不符合事務所的經營方針……我也是出於無奈。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그래? 지난번엔 실비아와 큰 문제 없이 일하지 않았었나?","JPN":"そうか？　前回はシルビアと手を組んでうまくやっていたじゃないか。","ENG":"Oh? But you had no problem working with Sylvia last time.","TWN":"是喔？你上次不是和希爾維亞合作得很愉快嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그 때는 형의 복수를 위해 큰 그림을 그리던 중이었거든.","JPN":"あの時は兄の復讐のためにビッグ・ピクチャーを描いていたからな。","ENG":"I was planning my brother’s revenge back then.","TWN":"因為我那時候的目的是要替哥哥報仇。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그나저나, 운전 중인 사람 옆에서 혼자 피자 먹으면 맛있나?","JPN":"ところで、運転で忙しい人の隣で食うピザは美味いか？","ENG":"Um, is it fun to eat pizza all by yourself, while I’m driving?","TWN":"我說你，非得在一個開車的人旁邊吃披薩嗎？這樣是有特別好吃嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"입 안에서 살살 녹지. 특히 구운 파인애플 토핑이 아주 일품이야.","JPN":"とろけるように美味いさ。とくにトッピングの焼いたパイナップルが絶品だ。","ENG":"Of course, it’s super fun. Pineapple, yum!","TWN":"起司都融化在嘴裡，超讚的！而且烤過的鳳梨更香甜呢！"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그쪽을 싫어할 만한 이유가 하나 더 생겼군.","JPN":"あんたを嫌いになる理由がもう一つできたな。","ENG":"Now I've got one more reason to hate you.","TWN":"我又多了一個討厭你的理由。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"파인애플 피자라니 제정신인가?","JPN":"パイナップルピザなんて正気か？","ENG":"What kind of maniac eats pineapple on a pizza?","TWN":"披薩怎麼可以加鳳梨？你是懂不懂吃？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"메이슨 씨가 괴로워하는 걸 보니 더 맛있게 느껴지는데.","JPN":"メイソンさんのその苦しそうな顔を見たら、もっとおいしく感じるな。","ENG":"Seeing you in pain makes it even more enjoyable, Mr. Mason.","TWN":"看你這麼生氣，我覺得披薩又更好吃了呢～"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그보다 운전이나 똑바로 하라고.","JPN":"それよりちゃんと運転しろよ。","ENG":"Anyway, pay attention to driving.","TWN":"不過可以請你專心開車嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이쪽은 이제 의뢰인이야. 돈을 받았으면 그만큼 일을 해야지.","JPN":"こっちは依頼主だぜ？　お金を受け取った分、しっかり働いてもらわないとな。","ENG":"I’m now your client. You’re being paid, and I expect you to work properly.","TWN":"我現在可是委託人，既然收了我的錢，就麻煩你認真一點。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"……내가 말을 말아야지.","JPN":"……はいはい。","ENG":"Oh man, why do I even bother...","TWN":"……我無法反駁。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그런데 이 침식지대에는 뭐 하러 온 거야?","JPN":"ところで、侵食地帯には何をしに来たんだ？","ENG":"By the way, why are we here in the Corrupted Area?","TWN":"不過我們來這裡要做什麼？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"꽤 오래 전부터 리플레이서 놈들이 쓰던 보급 시설이 있다는 모양이야.","JPN":"かなり昔からリプレイサーどもが使っていた補給施設があるらしい。","ENG":"I heard the Replacers had a supply depot here.","TWN":"來找很久以前克隆集團使用過的補給設施。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"내가 찾고 있던 물건이 거기로 옮겨졌다는 기록이 있었거든.","JPN":"俺が探している品物がそこに運ばれたという記録があってな。","ENG":"Also, there was a log stating the thing that I’m looking for was sent to that depot.","TWN":"有紀錄顯示我要找的東西被搬到那裡。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그래도 안심해. 여기 CSE 레벨은 낮은 편이니까.","JPN":"でも安心しろ。ここのCSEレベルは低いほうだから。","ENG":"Don’t worry, though. The CSE Level here is relatively low.","TWN":"不過安啦！這裡的CSE等級是偏低的。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"침식체라고 해 봤자 조무래기들 정도지.","JPN":"侵食体がいても雑魚程度さ。","ENG":"C.O.s here are a joke.","TWN":"就算是出現侵蝕體，也只是小角色而已。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"응?","JPN":"ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"아, 하긴 그쪽은 모를 수도 있겠군.","JPN":"ああ、説明が必要なようだな。","ENG":"Oh, you don’t know, do you?","TWN":"喔～你可能不太清楚，"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};